export const ACTIVITIES: Activity[] = [
  { id: "sample-brightpath-edu-1-email", accountId: "sample-brightpath-edu", kind: "email", summary: "Sent recap + proposed working session after intro meeting", body: "Emailed Marcus and Dana a recap of Tuesday's new business meeting: they want to move their marketing site and course-catalog frontend off self-hosted Next.js on EC2 because deploy times (~14 min) and preview environments are hurting the 6-person frontend team. Proposed a 60-min working session next week to whiteboard the migration path and get Dana's questions on SSO/SAML and SOC 2 answered. Marcus replied within the hour: 'this is exactly what we need, let me grab time.'", source: "SE follow-up email", occurredAt: daysAgo(3) },
  { id: "sample-brightpath-edu-2-meeting", accountId: "sample-brightpath-edu", kind: "meeting", summary: "First new business meeting with frontend + eng leadership", body: "Ran the intro meeting with Marcus Lee (Staff FE, champion), Dana Okafor (VP Eng), and Tomás from Product. Walked through Vercel's preview deployments and how they'd replace BrightPath's manual staging setup. Marcus lit up at branch previews; Dana was friendly but asked pointed questions about pricing predictability and whether they'd be locked in. No commercial numbers yet — agreed the next step is a technical working session before we talk POV.", source: "new business meeting", occurredAt: daysAgo(4) },
  { id: "sample-brightpath-edu-3-slack", accountId: "sample-brightpath-edu", kind: "slack", summary: "Marcus shared their current pain in eval channel", body: "In #sample-brightpath-edu-eval, Marcus vented that a hotfix to the enrollment landing page took 40 minutes to ship Friday because of their Jenkins + EC2 pipeline. Said he's been advocating internally for a managed frontend platform 'for like a year' and finally has Dana's attention now that they're planning the FY27 replatform. Tomás chimed in that Product wants faster preview links to review copy changes without pinging engineers.", source: "#sample-brightpath-edu-eval", occurredAt: daysAgo(6) },
  { id: "sample-brightpath-edu-4-call", accountId: "sample-brightpath-edu", kind: "call", summary: "Discovery call with Marcus to qualify before the meeting", body: "30-min qualification call with Marcus ahead of looping in leadership. Confirmed stack: Next.js 14 App Router, self-hosted on EC2 behind CloudFront, ~450k monthly visitors mostly during back-to-school. No current CDN strategy for their course pages. Marcus flagged that Selena Ruiz on DevOps owns the Jenkins + EC2 pipeline and will need to sign off on any migration — pragmatic but protective of the setup she maintains. Budget owner is Dana; Marcus said there's rough appetite around a $100-130k/yr range but nothing approved. This is genuinely early — no eval environment set up yet.", source: "discovery call", occurredAt: daysAgo(11) },
  { id: "sample-brightpath-edu-5-note", accountId: "sample-brightpath-edu", kind: "note", summary: "AM warm-intro context on why now", body: "Priya (AM) flagged that BrightPath just closed a Series B and is consolidating infra vendors ahead of a FY27 replatform. Marcus already knew Vercel by reputation from the Next.js community Slack and submitted our website inbound asking about managed hosting, which is what kicked this off. No competitor eval running that we know of — they're comparing against staying self-hosted more than against Netlify/AWS Amplify. Treat as a friendly, top-of-funnel new-business motion.", source: "AM handoff note", occurredAt: daysAgo(14) },
  { id: "sample-brightpath-edu-6-email", accountId: "sample-brightpath-edu", kind: "email", summary: "Inbound from Marcus requesting an intro conversation", body: "Marcus emailed cold via the website: 'Hi — we run Next.js self-hosted and it's becoming a maintenance burden for our small team. Would love 30 minutes to understand how Vercel handles previews and scaling for a site like ours.' Included their marketing domain and mentioned they're a K-12 curriculum platform (~90 employees). Routed to Priya, who tagged me in.", source: "inbound website email", occurredAt: daysAgo(18) },
  { id: "sample-civic-govtech-1-meeting", accountId: "sample-civic-govtech", kind: "meeting", summary: "Intro + discovery with Marcus Whitfield on portal modernization", body: "First working session with Marcus (Director of Platform Engineering). Civic GovTech runs 12 citizen-facing portals on an aging Drupal 9 + custom React setup, and their benefits-enrollment portal buckles during open-enrollment traffic spikes. Marcus wants to modernize onto Next.js and framed Vercel as the leading option but flagged up front that 'anything we buy has to survive procurement.' Confirmed ~$150K annual budget range for the platform line item.", source: "intro call", occurredAt: daysAgo(52) },
  { id: "sample-civic-govtech-2-call", accountId: "sample-civic-govtech", kind: "call", summary: "Technical deep dive on ISR + edge caching for enrollment portal", body: "Walked Marcus and Elena through ISR, edge functions, and how their benefits-enrollment portal would handle the January open-enrollment spike (they see ~40x baseline traffic for six weeks). Elena asked pointed questions about cold starts and cache invalidation on record updates. No blockers surfaced technically — Marcus said the arch 'clearly solves our scaling pain,' but wanted the security team looped in before going further.", source: "discovery call", occurredAt: daysAgo(44) },
  { id: "sample-civic-govtech-3-email", accountId: "sample-civic-govtech", kind: "email", summary: "Eng lead sends detailed compliance + architecture question list", body: "Marcus emailed a 14-item technical questionnaire ahead of the architecture session: FedRAMP Moderate authorization status, US data residency guarantees, WAF/DDoS posture, SSO via their Okta tenant, and audit-log export. Several items are hard requirements the CISO's office will gate on. I answered the platform questions and flagged that FedRAMP status is the one to align on early since it's a known procurement dependency.", source: "eng lead email", occurredAt: daysAgo(37) },
  { id: "sample-civic-govtech-4-meeting", accountId: "sample-civic-govtech", kind: "meeting", summary: "Architecture whiteboard: mapping 12 portals into Vercel projects", body: "90-minute deep dive with Marcus and two of his engineers. We mapped their existing monorepo — 12 apps sharing a component library — into a proposed Vercel project structure with a shared design system package. Debated migrating the enrollment portal first as the beachhead vs. the lower-risk 'find-a-service' directory. Landed on enrollment as the proof point. Marcus is genuinely invested and driving the technical eval, but no formal trial scope or success criteria signed off yet.", source: "architecture deep-dive", occurredAt: daysAgo(30) },
  { id: "sample-civic-govtech-5-slack", accountId: "sample-civic-govtech", kind: "slack", summary: "Elena deploys a preview of the directory portal, reacts positively", body: "In #civic-govtech-eval, Elena pushed a branch of their find-a-service directory and shared a Vercel preview URL. She wrote 'build went from 6 min on our CI to 90 seconds, and preview deploys per PR are going to change how we do design review.' Marcus reacted with a +1 and said this is exactly the developer-experience story he needs to show leadership. Encouraging technical validation, still informal / self-serve rather than a structured POV.", source: "#civic-govtech-eval", occurredAt: daysAgo(22) },
  { id: "sample-civic-govtech-6-note", accountId: "sample-civic-govtech", kind: "note", summary: "Security review kickoff with Raj Patel — FedRAMP concerns raised", body: "Raj Patel (Information Security Officer) joined for a security review kickoff and was openly skeptical. His two blockers: he wants documented FedRAMP Moderate authorization for any component touching PII, and he pushed back on where enrollment data would be cached at the edge. Said his office has 'killed two SaaS purchases in the last year over exactly this.' Sent him our compliance documentation and offered a call with our security team; he was noncommittal on timing.", source: "security review notes", occurredAt: daysAgo(16) },
  { id: "sample-civic-govtech-7-call", accountId: "sample-civic-govtech", kind: "call", summary: "Procurement reality check with CIO Sandra Okafor", body: "First real conversation with Sandra Okafor (CIO / economic buyer). She likes the direction Marcus is pushing but was blunt about the path: at $150K this exceeds their sole-source threshold, so it likely needs a formal RFP unless we qualify under an existing cooperative purchasing vehicle. Their capital budget for this is in next fiscal year, and the RFP-to-award cycle runs 6-9 months. She was cordial but not urgent — this is not on her critical path.", source: "procurement call", occurredAt: daysAgo(9) },
  { id: "sample-civic-govtech-8-slack", accountId: "sample-civic-govtech", kind: "slack", summary: "Marcus flags the eval is being paused pending FY budget", body: "Marcus DM'd me: 'Heads up — Sandra's office wants to hold anything net-new until the FY27 budget is finalized in the fall, and legal still hasn't cleared the procurement route. Technical fit isn't the issue, the timeline is.' The technical eval is effectively parked despite strong engineering buy-in. Deal is stalling on the government procurement cycle, not on product — flagging as at-risk.", source: "#civic-govtech-eval", occurredAt: daysAgo(6) },
  { id: "sample-fresco-grocers-1-note", accountId: "sample-fresco-grocers", kind: "note", summary: "Inbound: Priya Raman requested info after a Vercel Ship talk replay", body: "Priya Raman (Sr Frontend Eng) filled out the website contact form after watching a Vercel Ship replay on incremental migration. Her note said Fresco's storefront runs Nuxt 2 SSR on self-managed EC2 and full builds take ~18 min, which is slowing their team down. No timeline, budget, or project mentioned — flagged as low priority / very early.", source: "contact form / marketing lead", occurredAt: daysAgo(54) },
  { id: "sample-fresco-grocers-2-call", accountId: "sample-fresco-grocers", kind: "call", summary: "First discovery call — mapped current stack and pain points", body: "30-min intro with Priya and Dana Osei (Platform Eng). Storefront is Nuxt 2 SSR across 6 EC2 instances behind Cloudflare; weekend circular/promo launches spike traffic 4-5x and they manually pre-scale each Friday. They have no preview environments — QA runs on one shared staging box. Both were curious rather than committed: 'just seeing what's out there before our Q4 planning.'", source: "discovery call", occurredAt: daysAgo(47) },
  { id: "sample-fresco-grocers-3-email", accountId: "sample-fresco-grocers", kind: "email", summary: "Sent stack-fit recap + ISR/preview/migration docs to Priya", body: "Emailed a recap after the intro call with links to ISR, preview deployments, and the Nuxt-to-Next migration guide. Asked who owns the storefront roadmap and whether there is a funded initiative this year. Priya replied she'd circulate internally but was clear: 'we're not actively evaluating vendors yet, more scoping feasibility for ourselves.'", source: "email — Priya Raman", occurredAt: daysAgo(40) },
  { id: "sample-fresco-grocers-4-slack", accountId: "sample-fresco-grocers", kind: "slack", summary: "Eval channel spun up; Dana asking framework/migration questions", body: "Spun up #fresco-grocers-eval and added Priya and Dana. Dana asked whether they'd have to rewrite the whole Nuxt app at once or could move route-by-route, and whether Cloudflare could stay in front of Vercel. Confirmed incremental migration and CF passthrough both work. Still purely exploratory — no success criteria, no POV, no trial scoped.", source: "#fresco-grocers-eval", occurredAt: daysAgo(33) },
  { id: "sample-fresco-grocers-5-note", accountId: "sample-fresco-grocers", kind: "note", summary: "Internal: real technical fit but no funded project or exec sponsor yet", body: "Logged that Fresco is a genuine technical fit — 18-min builds, no previews, manual weekend scaling — but there is no funded initiative and no exec sponsor. Priya is a curious IC driving this on her own; Director of Eng Marcus Whitfield has not been in a single conversation. Keeping at low priority until we confirm a timeline. Rough ARR estimate ~200k if it ever becomes a real project.", source: "internal note", occurredAt: daysAgo(26) },
  { id: "sample-fresco-grocers-6-call", accountId: "sample-fresco-grocers", kind: "call", summary: "Follow-up call — no budget this FY, folding into Q4 planning", body: "Priya confirmed on a quick call that a storefront replatform is not budgeted this fiscal year; they'll fold it into Q4 planning and pick a direction then. She wants to bring in Marcus but he's heads-down on their in-store POS migration until August. Agreed to reconnect after their planning cycle — no commitment to a trial or POV.", source: "follow-up call", occurredAt: daysAgo(18) },
  { id: "sample-fresco-grocers-7-slack", accountId: "sample-fresco-grocers", kind: "slack", summary: "Priya: will loop in Marcus once the POS migration wraps", body: "In the eval channel Priya said the POS migration slipped to late August, so Marcus won't have bandwidth to look at the storefront until then. She still thinks Vercel is 'the likely direction' but can't move without his sign-off and a budget line. Asked me to check back in September before doing anything further.", source: "#fresco-grocers-eval", occurredAt: daysAgo(9) },
  { id: "sample-mesa-proptech-1-slack", accountId: "sample-mesa-proptech", kind: "slack", summary: "Marcus confirms internal sign-off and requests a commercial proposal", body: "Marcus messaged that he and Daniela briefed the CTO on the POV results and got a green light to standardize on Vercel. He asked for a formal quote covering 25 seats, ~4TB/mo bandwidth, and Enterprise support, targeting a decision before end of quarter. His words: 'Technical eval is done on our side, we just need numbers to take to finance.'", source: "#sample-mesa-proptech-eval", occurredAt: daysAgo(3) },
  { id: "sample-mesa-proptech-2-meeting", accountId: "sample-mesa-proptech", kind: "meeting", summary: "POV readout — all three exit criteria met, Daniela declared a technical win", body: "Formal readout with Daniela, Marcus, Ravi, and Yohanna from security. All three POV exit criteria were confirmed met, and Yohanna signed off after reviewing our SOC 2 Type II report and confirming US data residency for the listing data. Daniela said on the call 'technically this is a yes from us' and asked to see pricing for ~25 seats plus expected bandwidth. No open technical blockers remain.", source: "POV readout call", occurredAt: daysAgo(6) },
  { id: "sample-mesa-proptech-3-email", accountId: "sample-mesa-proptech", kind: "email", summary: "POV benchmark results clear the build-speed and ISR exit criteria", body: "Sent Daniela and Marcus the benchmark summary: production builds down from 22m to 3m48s, clearing the sub-5-min build criterion, and on-demand ISR revalidation firing reliably off their MLS webhook (100% of 500 test events revalidated under 2s), meeting the ISR-reliability criterion. Also flagged listing-page LCP improving from 3.8s to 1.1s at p75 as a bonus data point. With edge-middleware auth parity already resolved earlier in the eval, that leaves only the formal security review before the readout. Daniela replied 'this is very compelling, let's get the whole team on the readout.'", source: "eng lead email thread", occurredAt: daysAgo(13) },
  { id: "sample-mesa-proptech-4-slack", accountId: "sample-mesa-proptech", kind: "slack", summary: "Resolved edge middleware cookie issue that was blocking auth parity", body: "Ravi hit a blocker where the agent-portal session cookie wasn't propagating through edge middleware on preview URLs, which threatened the auth-parity exit criterion. Traced it to a missing domain scope on the cookie and fixed it with a middleware matcher config change, then confirmed parity with their Amplify behavior. Ravi: 'ok this is exactly the behavior we had before, nice — last thing I was worried about.'", source: "#sample-mesa-proptech-eval", occurredAt: daysAgo(21) },
  { id: "sample-mesa-proptech-5-meeting", accountId: "sample-mesa-proptech", kind: "meeting", summary: "POV kickoff — 3-week eval on a Pro trial team with signed-off exit criteria", body: "Kicked off the proof-of-value with Marcus and Ravi on a dedicated Pro team. Migrated the listings app repo and got a first preview deploy building in 4m12s versus 22m on Amplify, which visibly landed with the team. Set a readout date and three exit criteria signed off by Daniela: sub-5-min builds, reliable on-demand ISR via their MLS webhook, and edge middleware auth parity plus a security review pass.", source: "#sample-mesa-proptech-eval", occurredAt: daysAgo(30) },
  { id: "sample-mesa-proptech-6-meeting", accountId: "sample-mesa-proptech", kind: "meeting", summary: "Architecture deep-dive — mapped 180k ISR routes and middleware auth", body: "Reviewed Mesa's routing with Marcus: middleware-based auth for the agent portal and heavy on-demand ISR for ~180k listing pages driven by their MLS feed. Marcus's main concern was migrating their custom image pipeline, which we scoped to replace with Vercel Image Optimization. Used the session to draft the POV success criteria around build speed, ISR webhook reliability, and auth parity.", source: "solutions architecture session", occurredAt: daysAgo(41) },
  { id: "sample-mesa-proptech-7-call", accountId: "sample-mesa-proptech", kind: "call", summary: "Discovery call — build times and ISR pain on AWS Amplify", body: "Marcus Feld walked through Mesa's current stack: Next.js 14 self-hosted on AWS Amplify with 22-minute production builds blocking their 6-person frontend team. Daniela flagged that stale listing pages from ISR misfires are generating agent complaints and occasionally showing wrong pricing. Agreed the core evaluation goals are faster builds and reliable on-demand revalidation across their listing catalog.", source: "discovery call", occurredAt: daysAgo(48) },
  { id: "sample-nimbus-gaming-1-meeting", accountId: "sample-nimbus-gaming", kind: "meeting", summary: "Intro call — mapped web stack and Voltborn launch timeline", body: "First working session with Priya Raman (web platform lead) and EM Lena Ostrowski. Nimbus runs its player-facing web (marketing site, waitlist, patch notes, leaderboards) on Next.js Pages Router self-hosted on AWS ECS behind CloudFront, and is mid-migration to the App Router. Flagged the Voltborn global launch targeting late Q3 FY26 with a marketing drop they expect to push ~500K concurrent to the waitlist in the first hour. Priya wants to know whether Vercel can absorb that spike without the manual ECS pre-scaling and warm-up runbook they rely on today.", source: "intro call", occurredAt: daysAgo(52) },
  { id: "sample-nimbus-gaming-2-email", accountId: "sample-nimbus-gaming", kind: "email", summary: "Follow-up email — shared ISR + Fluid Compute references", body: "Sent Priya the architecture references on on-demand ISR and Fluid Compute concurrency after the intro. She replied describing their core pain: CloudFront invalidation for patch notes takes 3-5 minutes and they had stale-content incidents during the last two launches. Asked specifically how Vercel does targeted revalidation and whether draft/preview builds can be gated behind auth. Looped VP Eng Marcus Feld onto the thread — he acknowledged but didn't engage on specifics.", source: "priya raman email", occurredAt: daysAgo(44) },
  { id: "sample-nimbus-gaming-3-meeting", accountId: "sample-nimbus-gaming", kind: "meeting", summary: "Deep dive #1 — ISR, Edge Middleware, image optimization at launch scale", body: "90-minute technical deep dive with Priya, Lena, and infra engineer Deshawn Carter. Walked through on-demand ISR with cacheTag revalidation for patch notes and Edge Middleware for geo-routing players to regional leaderboards. Deshawn pushed hard on image optimization cost — the Voltborn key-art landing pages carry ~40 large hero assets and he's worried about per-transform pricing at 500K+ visitors. Left an action to model image optimization spend against expected launch traffic.", source: "technical deep dive", occurredAt: daysAgo(34) },
  { id: "sample-nimbus-gaming-4-slack", accountId: "sample-nimbus-gaming", kind: "slack", summary: "Eval channel — questions on revalidation limits + build concurrency", body: "In #nimbus-vercel-eval, Priya asked whether on-demand revalidation has rate limits they'd hit when they bulk-update ~2,000 leaderboard pages at season close, and how Vercel handles a thundering herd of simultaneous revalidations. Also asked about build concurrency since their monorepo ships 4 web apps. Answered inline with cacheTag batching guidance; she replied 'this is exactly the kind of thing that broke us on CloudFront last season.'", source: "#nimbus-vercel-eval", occurredAt: daysAgo(26) },
  { id: "sample-nimbus-gaming-5-note", accountId: "sample-nimbus-gaming", kind: "note", summary: "Internal note — Deshawn is the technical gatekeeper on cost + AWS pull-out", body: "Logging that Deshawn Carter is the main technical skeptic. His concern isn't capability — it's cost predictability under burst and pulling the web tier out of their existing AWS/Terraform setup. He wants a side-by-side of launch-day cost (Vercel vs current ECS + CloudFront) before he'll endorse. Priya is clearly the champion and aligned, but she was explicit that Marcus won't greenlight budget until Deshawn signs off on the scaling and cost story. Need to disarm Deshawn before we can credibly scope a POV.", source: "account note", occurredAt: daysAgo(18) },
  { id: "sample-nimbus-gaming-6-call", accountId: "sample-nimbus-gaming", kind: "call", summary: "Deep dive #2 — launch-day traffic spikes, Firewall rate limiting + Attack Mode", body: "Call focused on launch-day resilience. Their last title launch got hit with credential-stuffing and scalper bots on the waitlist, so Deshawn wanted to know how Vercel WAF rate limiting, bot management, and Attack Mode would cover that without them building it. Walked through Firewall custom rules plus a persistent Attack Mode challenge. Deshawn was noticeably warmer — said 'okay, this is the part I was actually worried about.' Fluid Compute concurrency on their /api/waitlist route (which calls their game backend) is still an open question — they need to confirm it won't overwhelm the downstream service.", source: "scaling deep dive call", occurredAt: daysAgo(11) },
  { id: "sample-nimbus-gaming-7-slack", accountId: "sample-nimbus-gaming", kind: "slack", summary: "Eval channel — Priya requests cost model, wants to lock deep dive #3", body: "Priya followed up in #nimbus-vercel-eval asking for the launch-day cost model (image optimization + Fluid invocations at 500K concurrent) that Deshawn needs, and proposed a third deep-dive with their infra team to whiteboard /api/waitlist backpressure and Fluid concurrency limits. She wants Marcus to join the back half of that session. Still no formal trial or POV scoped — they're gathering enough technical confidence to justify one. Confirmed the target is still a late Q3 FY26 Voltborn launch.", source: "#nimbus-vercel-eval", occurredAt: daysAgo(6) },
  { id: "sample-terra-agtech-1-call", accountId: "sample-terra-agtech", kind: "call", summary: "POV results review — p95 640ms, discussing adding a second sensor stream", body: "Walked through week-3 POV numbers with Priya and Dan: the TerraView dashboard p95 is down to 640ms from their 2.1s baseline, and Fluid Compute eliminated the cold starts they were hitting on soil-moisture queries. Priya wants to pull the weather-station stream into the POV to prove it holds at 12k concurrent sensors before she takes results to Marcus. Agreed to extend the POV environment two more weeks to cover that second source.", source: "POV results review call", occurredAt: daysAgo(3) },
  { id: "sample-terra-agtech-2-slack", accountId: "sample-terra-agtech", kind: "slack", summary: "Eval channel — Timescale connection pool exhaustion cleared under load", body: "Dan flagged in the eval channel that the POV ingestion function was exhausting their Timescale connection pool at ~8k sensors during a load test. Pointed him to the pooled connection string and to set maxDuration on the Fluid function; he redeployed and the pool errors cleared. Confirmed we can now push to 12k sensors without connection errors.", source: "#sample-terra-agtech-eval", occurredAt: daysAgo(6) },
  { id: "sample-terra-agtech-3-note", accountId: "sample-terra-agtech", kind: "note", summary: "Logged week-2 POV benchmarks against success criteria", body: "Recorded the week-2 POV benchmark run against the agreed exit criteria: p95 dashboard load 710ms (target <800ms, pass), ingestion sustained 10.5k sensors in test (target 12k, still ramping), estimated monthly compute ~$1.4k (inside Marcus's budget). Two of three success criteria are green; sustained throughput is the one open item. Need a single clean 12k run to call this a technical win.", source: "POV benchmark notes", occurredAt: daysAgo(12) },
  { id: "sample-terra-agtech-4-meeting", accountId: "sample-terra-agtech", kind: "meeting", summary: "POV mid-point checkpoint — early results look promising", body: "Mid-POV checkpoint with Priya and Dan on the field-data pipeline. Streaming the soil-moisture dashboard through ISR plus Fluid Compute already cut p95 roughly in half in the test env, and the team was genuinely surprised by the cold-start improvement. Rebecca from security joined for 10 minutes and asked about data residency for EU grower data — logged as a follow-up we must resolve before any production commit.", source: "POV mid-point checkpoint", occurredAt: daysAgo(18) },
  { id: "sample-terra-agtech-5-meeting", accountId: "sample-terra-agtech", kind: "meeting", summary: "POV kickoff — provisioned eval project, wired first data source", body: "Kicked off the POV: provisioned the isolated Vercel project, connected their Timescale field-sensor DB, and deployed a first ingestion function with Dan pairing. Had the soil-moisture dashboard rendering live test data by the end of the session. Priya set the goal of proving this out before Terra's fall planting-season load hits.", source: "POV kickoff", occurredAt: daysAgo(24) },
  { id: "sample-terra-agtech-6-email", accountId: "sample-terra-agtech", kind: "email", summary: "Confirmed POV scope and written success criteria", body: "Sent the POV plan to Priya and Marcus and got sign-off: scope is the soil-moisture ingestion pipeline plus the grower dashboard, running in an isolated Vercel POV project. Written success criteria are p95 dashboard load under 800ms, sustain 12k sensors, and monthly compute under $2k. Two-week POV window agreed, with Priya as technical owner and a results review at the end.", source: "POV scoping email", occurredAt: daysAgo(31) },
  { id: "sample-terra-agtech-7-call", accountId: "sample-terra-agtech", kind: "call", summary: "Discovery — self-managed pipeline cold starts and scaling ceiling", body: "Discovery with Priya and Marcus on their current setup: a self-managed field-data pipeline on ECS that struggles with cold starts and can't cleanly scale past ~9k sensors during peak irrigation windows. Marcus is cost-conscious after their Series B and wants concrete proof before switching platforms. Agreed the fastest path to conviction is a scoped POV on the soil-moisture pipeline.", source: "discovery call", occurredAt: daysAgo(48) },
  { id: "acme-robotics-1-slack", accountId: "acme-robotics", kind: "slack", summary: "InfoSec still needs SAML SCIM answers before green-lighting POV", body: "Priya posted in the eval channel that she can't approve a POV until we return the vendor security questionnaire, specifically SAML with SCIM auto-deprovisioning and whether audit logs export to their Splunk instance. Daniel replied that he wants the POV to start next week and asked me to turn the questionnaire around by Thursday. I confirmed Enterprise SSO/SAML + directory sync are supported and committed to returning the completed written answers by Thursday — our SOC 2 Type II and ISO 27001 are already with her from the earlier thread.", source: "#acme-robotics-eval", occurredAt: daysAgo(3) },
  { id: "acme-robotics-2-email", accountId: "acme-robotics", kind: "email", summary: "EU data-residency question from Berlin team blocking scope sign-off", body: "Sofia emailed asking whether function execution and edge middleware for their EU-facing dashboard can be pinned to Frankfurt (fra1) and whether any customer PII would leave the EU, citing their GDPR posture. She needs this documented before she'll sign off on the POV scope. I replied outlining regional function config and pointed to our DPA, but flagged internally that we still owe them a written data-residency statement.", source: "eu frontend email", occurredAt: daysAgo(6) },
  { id: "acme-robotics-3-meeting", accountId: "acme-robotics", kind: "meeting", summary: "Deep-dive technical workshop on migration architecture with platform team", body: "Ran a 90-minute working session with Daniel, Liam, and two of their frontend engineers walking through their current setup: 3 Next.js apps on self-managed AWS + CloudFront, ~40 min CI builds, and a monorepo they want to split. We whiteboarded a migration to Vercel with preview deployments and ISR, and Liam pushed hard on build cache behavior for their monorepo. No commercial talk — this was purely validating fit against their real stack.", source: "technical deep-dive workshop", occurredAt: daysAgo(11) },
  { id: "acme-robotics-4-note", accountId: "acme-robotics", kind: "note", summary: "CFO not yet engaged; Daniel controls eval budget for now", body: "Debrief note after the workshop: Daniel confirmed he owns the technical decision but any spend above his $50k discretionary threshold routes to Dana Whitfield (CFO), who has not been in a single conversation yet. Daniel wants to prove technical value via the POV before bringing Dana in. Flag: no economic buyer engagement is our biggest gap — need a value narrative ready for finance once the POV lands.", source: "internal deal note", occurredAt: daysAgo(13) },
  { id: "acme-robotics-5-call", accountId: "acme-robotics", kind: "call", summary: "Champion call to define POV success criteria and blockers", body: "Call with Daniel to scope the POV. He wants a 3-week trial migrating their customer-portal app, with success defined as sub-10-min builds and working preview environments per PR. He named two gates before we can start: (1) InfoSec sign-off on SSO/SAML, owned by Priya, and (2) the EU data-residency answer for the Berlin team. Daniel is fully bought in and offered to escalate internally if security drags.", source: "discovery/champion call", occurredAt: daysAgo(18) },
  { id: "acme-robotics-6-email", accountId: "acme-robotics", kind: "email", summary: "Sent SOC 2 + ISO 27001 to Priya; skeptical reply flagging SAML/SCIM gaps", body: "Priya sent over Acme's 60-question vendor security questionnaire, and I returned our SOC 2 Type II and ISO 27001 reports as initial evidence while we work up the full written response. She replied same day flagging three concerns: SAML metadata rotation, whether SCIM handles group-based role mapping, and data processing sub-locations. Her tone was firmly skeptical — 'we've been burned by a SaaS vendor's SSO gaps before' — so this review will need careful handling.", source: "infosec email thread", occurredAt: daysAgo(22) },
  { id: "acme-robotics-7-meeting", accountId: "acme-robotics", kind: "meeting", summary: "Discovery call uncovered scaling pain and DX frustration", body: "Initial discovery with Daniel and Liam. Root problem: their AWS-hosted Next.js apps have 40-minute CI pipelines and no preview environments, so frontend velocity is stalling as they grow the team from 12 to 20 engineers. Daniel described it as 'our infra is now a tax on shipping.' Strong pain and clear technical fit — agreed to move to a hands-on technical deep-dive as the next step.", source: "discovery call", occurredAt: daysAgo(29) },
  { id: "aperture-labs-1-call", accountId: "aperture-labs", kind: "call", summary: "Discovery call — Fleetsense dashboard migration off self-managed EKS", body: "Priya Nair walked through the current setup: their Fleetsense operator dashboard is a Next.js 14 app self-hosted on EKS, serving ~40k daily operator sessions across NA and EU plants. Top pains are 18-minute cold builds, no preview environments, and an infra team buried in toil. She framed the whole evaluation around one question: can Vercel front their existing Go/gRPC telemetry API without a rewrite.", source: "discovery call", occurredAt: daysAgo(46) },
  { id: "aperture-labs-2-meeting", accountId: "aperture-labs", kind: "meeting", summary: "Architecture deep-dive — BFF pattern over the gRPC telemetry API", body: "Reviewed how Route Handlers would sit in front of their internal gRPC telemetry service (grpc-web vs. a thin REST gateway). Tomás Rivera flagged that a 24h sensor window can return a 2-3MB payload and pressed on function payload and timeout limits. We agreed to test Fluid Compute with streaming responses for the large reads, and Priya is keen to move plant-config pages to ISR.", source: "architecture review (Zoom)", occurredAt: daysAgo(31) },
  { id: "aperture-labs-3-email", accountId: "aperture-labs", kind: "email", summary: "Email from Priya: six integration/latency questions before any POV", body: "Priya sent a numbered list she wants answered before committing to a pilot: (1) p95 for edge middleware auth against their Keycloak, (2) can functions be pinned to eu-central-1 for German plant data residency, (3) MQTT-to-websocket bridge compatibility, (4) ISR revalidation triggered by a webhook from their Go backend, (5) remote build cache for their Turborepo monorepo, (6) OIDC for CI. I answered 1, 4, and 6 inline and owe her a written doc covering 2, 3, and 5.", source: "eng lead email", occurredAt: daysAgo(22) },
  { id: "aperture-labs-4-slack", accountId: "aperture-labs", kind: "slack", summary: "Slack: EU operator latency target of sub-200ms TTFB", body: "In #aperture-labs-eval, Priya shared that EU operators currently see ~600ms TTFB served from a us-east origin, and the target is under 200ms. I proposed multi-region functions plus edge middleware and offered to wire a benchmark against their staging telemetry. Devan Osei jumped in with pointed questions about exactly where telemetry gets cached and whether any PII ever transits US regions.", source: "#aperture-labs-eval", occurredAt: daysAgo(18) },
  { id: "aperture-labs-5-note", accountId: "aperture-labs", kind: "note", summary: "Internal note — deal shape, open technical items, stakeholder map", body: "Priya is a strong, technically fluent champion driving the eval; economic buyer Marcus Feld (VP Eng) has only been cc'd and will need a business case before he engages. Open technical items gating a POV: EU data residency guarantee for Devan, large-payload streaming, and monorepo build caching. No POV scheduled yet — we're still clearing architecture questions. Sizing lands around 360k ARR on Enterprise.", source: "account notes", occurredAt: daysAgo(13) },
  { id: "aperture-labs-6-meeting", accountId: "aperture-labs", kind: "meeting", summary: "Deep-dive #2 — streaming large telemetry + eu-central-1 pinning", body: "Walked Priya and Tomás through streaming Route Handlers on Fluid Compute for the 2-3MB telemetry reads; the live demo held the response comfortably under memory limits and Tomás is now satisfied on payloads. Confirmed function region pinning to eu-central-1 satisfies residency for the German plants. Remaining blocker: Devan still wants a full infra security review before any POV, and Priya agreed to set that up.", source: "technical deep-dive (Zoom)", occurredAt: daysAgo(7) },
  { id: "aperture-labs-7-slack", accountId: "aperture-labs", kind: "slack", summary: "Slack: Priya wants to scope a POV once the security review clears", body: "Priya messaged that Tomás has signed off on the streaming approach and she's pushing Devan to book his security review next week. She asked what a 2-week POV would scope and is proposing the EU operator dashboard as the pilot surface. She's not committing until I send the written multi-region latency numbers, which she wants to show Marcus.", source: "#aperture-labs-eval", occurredAt: daysAgo(4) },
  { id: "blue-sun-telecom-1-slack", accountId: "blue-sun-telecom", kind: "slack", summary: "Priya shares revised peak concurrency numbers to feed the quote", body: "Priya dropped their revised peak load in the eval channel: bill-run spikes hit ~9,400 req/s for a ~20-min window on the 1st and 15th, sustained ~2,100 req/s otherwise. She asked whether Fluid compute concurrency absorbs the burst without cold-start penalty on the account-portal auth middleware. Confirmed it does, but flagged we need to size function concurrency and the committed bandwidth tier around those spikes — pulling both into the quote now.", source: "#blue-sun-telecom-eval", occurredAt: daysAgo(4) },
  { id: "blue-sun-telecom-2-meeting", accountId: "blue-sun-telecom", kind: "meeting", summary: "Capacity/sizing workshop with Platform, Architecture, VP + procurement", body: "Ran the sizing workshop with Priya (Platform), Devin (Architecture), and Marcus (VP Digital), with procurement dialed in. Walked 120M monthly requests and 45 dev seats across the portal, network-ops, and marketing teams, and agreed Enterprise is the right SKU. Open items: whether the 99.99% SLA needs the dedicated support add-on and how to price the WAF for the customer-facing account portal. Marcus wants a single itemized quote he can hand to finance.", source: "sizing workshop — Blue Sun + Vercel", occurredAt: daysAgo(8) },
  { id: "blue-sun-telecom-3-email", accountId: "blue-sun-telecom", kind: "email", summary: "InfoSec gates the SLA numbers before the scoping doc goes to committee", body: "Sandra Ochoa replied on the SLA thread: their downstream carrier contracts obligate 99.99% on the self-service portal, so any Vercel SLA below that is a non-starter for sizing. She wants the SLA commitment, incident-response times, and DDoS/WAF coverage written into the scoping doc before it reaches the committee. Not blocking the deal, but explicitly gating the numbers — need to confirm our Enterprise 99.99% SLA language in writing.", source: "InfoSec email — S. Ochoa", occurredAt: daysAgo(14) },
  { id: "blue-sun-telecom-4-call", accountId: "blue-sun-telecom", kind: "call", summary: "Traffic-profiling call to model bandwidth and invocations", body: "Traffic-profiling call with Devin and Tomás — pulled their CDN logs together: 118M req/mo, ~68% cacheable (plan and pricing pages are strong ISR candidates), the remainder dynamic account/billing views. Peak concurrency during monthly bill runs is the true sizing driver; everything else sits comfortably inside default limits. Action on me to model committed bandwidth and function invocations off these figures to feed the quote.", source: "traffic profiling call", occurredAt: daysAgo(22) },
  { id: "blue-sun-telecom-5-note", accountId: "blue-sun-telecom", kind: "note", summary: "Internal capacity-planning note; ACV lands ~$890K", body: "Capacity planning for the quote: assume 120M req/mo baseline with ~15% YoY growth and two predictable bill-run spikes per month. Recommending Enterprise with a committed bandwidth tier, Fluid compute for the portal middleware, and the observability add-on (they have effectively no edge observability today). Rough ACV lands ~$890K including the SLA and WAF line items — need Priya to confirm final seat count before I lock the quote.", source: "internal sizing note", occurredAt: daysAgo(30) },
  { id: "blue-sun-telecom-6-email", accountId: "blue-sun-telecom", kind: "email", summary: "Priya sends team breakdown to set the seat basis at 45", body: "Priya sent the team breakdown to size seats: 22 on the account-portal squad, 14 on network-ops tooling, and 9 on the marketing site = 45 total, with a possible +6 in Q4. She confirmed they want everyone on Enterprise (not a split plan) for unified RBAC and audit logs — a security-committee requirement from Sandra's team. This sets the seat basis for scoping the deal.", source: "eng lead email — P. Nadkarni", occurredAt: daysAgo(41) },
  { id: "blue-sun-telecom-7-meeting", accountId: "blue-sun-telecom", kind: "meeting", summary: "POV readout closes technical win; Marcus greenlights commercial scoping", body: "Readout closing the account-portal POV — middleware auth, ISR on pricing pages, and preview deploys all validated by Devin's team, so the proof-of-value passed. Marcus gave verbal go to move into commercial sizing/scoping and named the buying committee: Platform, Architecture, InfoSec, procurement, and finance. Transitioning from technical validation to scoping the Enterprise footprint and SLA; next step is the capacity/sizing workshop.", source: "technical win recap — eval readout", occurredAt: daysAgo(52) },
  { id: "cyberdyne-systems-1-slack", accountId: "cyberdyne-systems", kind: "slack", summary: "Marcus confirms he wants to sign this quarter, waiting on security", body: "Marcus Vale posted in #cyberdyne-systems-eval: 'Numbers on the order form look right to me and I've told finance to expect it. The only thing between us and signature is Priya's SOC 2 review. I want this wrapped before end of quarter, so let's get her whatever she needs.' Devin thumbs-upped and tagged Priya's team.", source: "#cyberdyne-systems-eval", occurredAt: daysAgo(2) },
  { id: "cyberdyne-systems-2-email", accountId: "cyberdyne-systems", kind: "email", summary: "Sent revised order form: $620K ARR, 3-yr Enterprise + Firewall add-on", body: "Emailed Marcus and Rachel the updated quote after removing the extra 2 concurrent build seats: $620,000 ARR on a 3-year term, Enterprise plan with the WAF/DDoS add-on and 99.99% SLA, 8% multi-year discount already baked in. Payment terms net-45 per Rachel's request. Order form valid through July 31 to land in Q3 FY26.", source: "quote / order form email", occurredAt: daysAgo(5) },
  { id: "cyberdyne-systems-3-call", accountId: "cyberdyne-systems", kind: "call", summary: "Security review call with Priya - flagged data residency & subprocessor list", body: "Priya Nandkumar walked through her checklist on a 45-min call. Two open items block her sign-off: confirmation that Cyberdyne's build/runtime workloads can be pinned to us-east regions only, and an updated subprocessor list for their vendor risk register. She was blunt: 'I'm not signing anything until data residency is in writing.' I committed to sending the DPA and region-pinning docs by Wednesday.", source: "security review call", occurredAt: daysAgo(7) },
  { id: "cyberdyne-systems-4-note", accountId: "cyberdyne-systems", kind: "note", summary: "Procurement wants net-45 and a mutual NDA before PO issues", body: "Debrief after syncing with Rachel Tanaka: legal is fine with our MSA redlines but procurement won't cut a PO until net-45 terms are reflected on the order form and a mutual NDA is countersigned. Rachel estimates 3-4 business days once the final form lands. She's neutral but not an obstacle - this is process, not resistance.", source: "procurement sync notes", occurredAt: daysAgo(11) },
  { id: "cyberdyne-systems-5-meeting", accountId: "cyberdyne-systems", kind: "meeting", summary: "Pricing readout to Marcus - verbal go on 3-year Enterprise", body: "Presented three packaging options to Marcus and Devin. Marcus chose the 3-year Enterprise commitment for the discount and locked-in pricing, explicitly to protect budget ahead of their own funding round. He gave a verbal 'let's do it' and asked us to formalize a quote, contingent only on security clearing it. Devin confirmed the POV metrics (build times down 41%, p95 latency down 32%) already justify the spend internally.", source: "pricing readout meeting", occurredAt: daysAgo(16) },
  { id: "cyberdyne-systems-6-email", accountId: "cyberdyne-systems", kind: "email", summary: "Devin shares internal POV summary he's circulating to leadership", body: "Devin Cho forwarded the one-pager he's socializing internally: migrating their 3 customer-facing consoles to Vercel cut deploy times from 14 min to ~8 min and eliminated their self-managed CDN. He wrote 'this is a no-brainer, I just need Marcus to see the ARR justification and Priya to bless the compliance side.' Strong champion momentum heading into the quote.", source: "eng lead email", occurredAt: daysAgo(22) },
  { id: "gekko-capital-1-slack", accountId: "gekko-capital", kind: "slack", summary: "Nudged Marcus in #gekko-capital-eval — quiet, POV effectively paused", body: "Pinged Marcus for a status check; he says he got pulled onto a quarter-close production incident and hasn't touched the POV in ~10 days. SAML SSO is still blocked on Priya, who owns the Okta admin approval, and the InfoSec questionnaire is still stalled with Dana Cho's team, who never engaged after the initial request. Offered to run a hands-on working session to knock out the Okta app registration together if he can borrow 30 min from an admin — no date committed.", source: "#gekko-capital-eval", occurredAt: daysAgo(5) },
  { id: "gekko-capital-2-email", accountId: "gekko-capital", kind: "email", summary: "Priya pushes the mid-POV review a second time — 'after our planning cycle'", body: "Priya replied to my scheduling email asking to move the mid-POV readout to 'after our planning cycle wraps,' the second reschedule in three weeks. She didn't respond to the Okta admin request or the nudge to release the InfoSec questionnaire. Looped in Rachel (AM) to find out whether there's an exec sponsor above Priya we can lean on before the POV window closes.", source: "sponsor email", occurredAt: daysAgo(12) },
  { id: "gekko-capital-3-note", accountId: "gekko-capital", kind: "note", summary: "Risk note — sponsor stretched thin, POV timeline slipping past the 4-week window", body: "Logging this as at-risk. Priya's org is mid-reorg and she's underwater; she owns the Okta admin approval that's blocking SSO and won't spend the political capital to get Dana Cho's InfoSec team to start the sign-off. Marcus is genuinely engaged but has zero authority to unblock either. Activity in #gekko-capital-eval has dropped off a cliff and we're now drifting past the original 4-week plan with no firm decision date holding.", source: "internal CRM note", occurredAt: daysAgo(19) },
  { id: "gekko-capital-4-call", accountId: "gekko-capital", kind: "call", summary: "Mid-POV check-in — progress stalled on Okta SAML; Priya a no-show", body: "Only Marcus and Tom Reyes joined; Priya dropped 10 minutes before start. Marcus is blocked wiring Okta SAML because registering the app needs an IdP admin and Priya owns that approval. He's also unwilling to push further into prod-like config without Dana Cho's InfoSec sign-off, which hasn't started. Two of the four success criteria are unstarted with the original 4-week window nearly up.", source: "mid-POV check-in call", occurredAt: daysAgo(27) },
  { id: "gekko-capital-5-slack", accountId: "gekko-capital", kind: "slack", summary: "Marcus shipped first preview deploy — build 4m12s vs ~22min on Jenkins", body: "Marcus got the Portfolio Insights staging branch deploying on Vercel and posted a screenshot in #gekko-capital-eval: first preview build landed at 4m12s versus ~22 minutes on their current Jenkins pipeline. Strong early signal on the headline success metric. Still no SSO wired up and the InfoSec questionnaire remains untouched.", source: "#gekko-capital-eval", occurredAt: daysAgo(34) },
  { id: "gekko-capital-6-email", accountId: "gekko-capital", kind: "email", summary: "Enterprise trial access provisioned; Marcus to start on Portfolio Insights repo", body: "Sent Marcus the enterprise trial team invite and walked through connecting the Portfolio Insights GitHub repo for the POV. He confirmed he'd deploy from a staging branch to avoid touching prod CI. Asked Dana Cho to kick off the security questionnaire (SOC 2, EU data residency) in parallel so it isn't a last-minute blocker — no reply from her yet.", source: "eng lead email thread", occurredAt: daysAgo(45) },
  { id: "gekko-capital-7-meeting", accountId: "gekko-capital", kind: "meeting", summary: "POV kickoff — scoped Portfolio Insights migration, 4-week plan, success criteria signed off", body: "Kicked off the 4-week POV with Priya Nair sponsoring and Marcus Feld driving hands-on. Agreed success criteria: migrate the Portfolio Insights internal dashboard to Vercel, cut the current 22-min Jenkins build to under 5 min, prove Okta SAML SSO, and secure InfoSec sign-off on SOC 2 plus EU data residency. Target a go/no-go decision by end of Q3 FY26; Priya flagged upfront that her team is mid-reorg so her own bandwidth would be tight.", source: "POV kickoff call", occurredAt: daysAgo(53) },
  { id: "globex-media-1-slack", accountId: "globex-media", kind: "slack", summary: "Marcus confirms bake-off decision internally, loops in pricing", body: "Marcus posted in #globex-media-eval: 'Team's aligned — Vercel wins the bake-off. Fluid cold starts came in at 340ms vs Fastly Compute's 1.2s on our bidder endpoint, and the Edge Config rollout killed the 90s config-propagation lag we hated.' He asked us to bring pricing into the next call so they can start budgeting. Danielle to loop in Priya on our side.", source: "#globex-media-eval", occurredAt: daysAgo(3) },
  { id: "globex-media-2-email", accountId: "globex-media", kind: "email", summary: "Marcus emails the final POC scorecard, Vercel selected over incumbent", body: "Marcus sent the completed evaluation scorecard: Vercel 47/50, incumbent Fastly Compute@Edge 38/50. Vercel won decisively on p99 latency (112ms vs 210ms under 40k RPS load test), DX, and rollback speed; incumbent only edged ahead on their existing contract price. Marcus wrote 'This is the platform we want to build the next-gen bidder on — let's talk commercials.'", source: "eng lead email (Marcus Feng)", occurredAt: daysAgo(5) },
  { id: "globex-media-3-meeting", accountId: "globex-media", kind: "meeting", summary: "Bake-off readout call — Vercel declared the technical winner", body: "Live readout with Marcus, Ravi, Sofia, and Derek reviewing head-to-head results on the real-time bidder workload. Ravi walked through the load-test dashboards: Vercel held 112ms p99 at 40k RPS where Fastly degraded past 30k. Derek's earlier concern about multi-region config consistency was resolved by Edge Config's sub-second propagation, and he signed off. Sofia asked about pricing model, we agreed to bring commercials next.", source: "bake-off readout call", occurredAt: daysAgo(8) },
  { id: "globex-media-4-slack", accountId: "globex-media", kind: "slack", summary: "Derek's last blocker cleared after Edge Config consistency test passes", body: "In #globex-media-eval, Derek wrote: 'Ran the config-flip test across iad1/sfo1/cdg1 — propagation was consistently under 800ms, no stale reads. That was my one hard blocker, it's gone.' Ravi replied confirming the observability hooks into their Datadog setup worked out of the box. This was the last open technical objection before the team's decision.", source: "#globex-media-eval", occurredAt: daysAgo(11) },
  { id: "globex-media-5-call", accountId: "globex-media", kind: "call", summary: "Load-test deep dive with Ravi — Vercel outperforms incumbent under peak", body: "Working session with Ravi to run the 40k RPS synthetic auction load against both platforms. Vercel on Fluid compute sustained 112ms p99 with no cold-start cliff; Fastly Compute@Edge started shedding requests above 32k RPS. Ravi captured the numbers for the scorecard and said 'this basically settles it for the infra team.'", source: "load-test working session", occurredAt: daysAgo(16) },
  { id: "globex-media-6-note", accountId: "globex-media", kind: "note", summary: "POC scope agreed: replicate bidder endpoint on both platforms", body: "Kicked off the head-to-head POC. Scope: port their real-time bidder edge endpoint to Vercel Fluid + Edge Config and mirror it on incumbent Fastly Compute@Edge, then compare p99 latency, cold starts, config-propagation, and rollback. Marcus is sponsoring, Ravi is doing the build, Derek (SRE) flagged multi-region config consistency as the pass/fail criterion he cares about.", source: "POC kickoff notes", occurredAt: daysAgo(24) },
  { id: "globex-media-7-meeting", accountId: "globex-media", kind: "meeting", summary: "Discovery — pain with incumbent's config lag and cold starts", body: "Discovery with Marcus and Sofia. Their ad bidder on Fastly suffers ~90s config-propagation lag causing stale bid rules, plus cold-start spikes hurting win-rate during traffic bursts. Sofia framed it as a $220k platform decision and wants a real bake-off before committing. Set up the head-to-head POC as the next step.", source: "discovery call", occurredAt: daysAgo(31) },
  { id: "hooli-financial-1-meeting", accountId: "hooli-financial", kind: "meeting", summary: "Technical deep-dive workshop on their Next.js migration with the platform team", body: "Ran a 90-minute architecture workshop with Priya Raman and two of her engineers. Their monorepo holds three customer-facing apps currently self-hosted on AWS ECS behind CloudFront; the biggest pains are 25-minute CI builds and no per-branch preview environments. Priya wants to evaluate Vercel specifically for ISR on the account-dashboard app (~4M monthly logged-in sessions) and asked us to map Edge Middleware onto their existing auth-at-the-edge setup.", source: "deep dive workshop", occurredAt: daysAgo(52) },
  { id: "hooli-financial-2-email", accountId: "hooli-financial", kind: "email", summary: "Priya sends architecture diagram and an 11-item technical requirements checklist", body: "Priya emailed over their Miro architecture export plus a checklist of 11 requirements she needs answered before taking this wider internally. Top asks: ISR revalidation semantics under their traffic, Edge Middleware cost at 4M sessions, and whether Fluid Compute changes their concurrency billing. She flagged that US-only data residency is non-negotiable for their PCI scope.", source: "eng lead email", occurredAt: daysAgo(45) },
  { id: "hooli-financial-3-call", accountId: "hooli-financial", kind: "call", summary: "Deep dive on CI/CD, Turborepo remote caching, and preview deployments", body: "45-minute call walking through how Vercel preview deployments would replace their bespoke Jenkins preview stack. They run a Turborepo, and we confirmed remote caching should cut their 25-minute builds to under 6. The open technical question is how to feed their existing Datadog RUM and OTel traces into Vercel observability without double-instrumenting each app.", source: "discovery call", occurredAt: daysAgo(38) },
  { id: "hooli-financial-4-slack", accountId: "hooli-financial", kind: "slack", summary: "AppSec lead raises SOC 2 and data-residency blockers in the eval channel", body: "In #hooli-financial-eval, Owen Delacroix asked for our SOC 2 Type II report, a signed DPA, and written confirmation that all compute and logs stay in us-east. He's openly skeptical about moving customer-facing fintech workloads to a managed platform and wants WAF + DDoS specifics before he'll endorse. Priya backed us in-thread and offered to stand up a dedicated security review.", source: "#hooli-financial-eval", occurredAt: daysAgo(30) },
  { id: "hooli-financial-5-note", accountId: "hooli-financial", kind: "note", summary: "Champion Priya Raman is leaving Hooli — deal now at risk", body: "Confirmed with the AM that Priya Raman has given notice; her last day is end of month. She was driving the entire evaluation and owned the internal business case, and there's no named successor for the platform-eng lead role yet. The deep dive is effectively frozen until we re-establish a sponsor. Marking the account at-risk.", source: "internal note", occurredAt: daysAgo(21) },
  { id: "hooli-financial-6-email", accountId: "hooli-financial", kind: "email", summary: "Cold-ish outreach to VP Eng Dana Whitcomb to re-establish sponsorship", body: "Emailed Dana Whitcomb recapping where the evaluation stood and the ROI on build times and infra consolidation. Kept it to 20-minute-meeting length and asked who inherits Priya's platform initiatives. No reply after eight days; the AM says Dana is heads-down on their Series C close and unlikely to engage this month.", source: "VP eng email", occurredAt: daysAgo(14) },
  { id: "hooli-financial-7-slack", accountId: "hooli-financial", kind: "slack", summary: "Marcus Feldt tentatively agrees to keep the eval alive but isn't a champion yet", body: "Marcus Feldt, a Staff Engineer Priya trusted, replied in #hooli-financial-eval that he can \"keep the lights on\" but isn't the decision owner and needs to re-baseline the requirements himself. He never saw the architecture work Priya and I did and wants a recap deck before committing time. Cautiously positive, but clearly not yet a sponsor.", source: "#hooli-financial-eval", occurredAt: daysAgo(6) },
  { id: "hooli-financial-8-note", accountId: "hooli-financial", kind: "note", summary: "Re-engagement plan to rebuild the deep dive around Marcus", body: "Plan: send Marcus a tight recap of Priya's 11 requirements with our answers, then re-run a condensed deep-dive session to establish him as the new sponsor. In parallel, use Owen's pending security review as a wedge to pull Dana back in on the PCI and data-residency angle. Need to reconfirm the account-dashboard app as the beachhead before we can credibly propose a POV.", source: "internal note", occurredAt: daysAgo(3) },
  { id: "initech-cloud-1-email", accountId: "initech-cloud", kind: "email", summary: "Priya: still interested but can't get manager time this quarter", body: "Priya replied to my check-in: 'Still keen on this personally — the preview speed alone would help us. But Dana's slammed with Q3 roadmap and I can't get 30 min to make the case. Let's pick back up after our planning freeze lifts.' She asked me to keep the shared channel warm. No path to a sponsor conversation yet; next touch is to re-engage once their freeze ends.", source: "eng lead email", occurredAt: daysAgo(6) },
  { id: "initech-cloud-2-note", accountId: "initech-cloud", kind: "note", summary: "Internal: IC-led, no sponsor, keeping as low-priority discovery", body: "Qualification note to self: genuine technical interest from Priya (champion) and Marcus (user), but this is entirely engineer-driven curiosity. No economic buyer engaged, no budget, no timeline, no compelling event. Dana Kwon (EM) is the likely sponsor but hasn't joined a single touch. Holding stage = Discovery, priority = low until someone with budget shows up.", source: "internal CRM note", occurredAt: daysAgo(15) },
  { id: "initech-cloud-3-meeting", accountId: "initech-cloud", kind: "meeting", summary: "Screenshare walkthrough of previews + build times with Priya & Marcus", body: "45-min screenshare. Walked Priya and Marcus through a sample PR preview and remote caching; Marcus was impressed the demo build dropped from ~8 min to ~2 min. Both engineers engaged, but when I asked about next steps toward a trial migration Priya said 'I need to find time to raise it with Dana — we haven't prioritized it.' No decision made and no eval plan set.", source: "tech walkthrough", occurredAt: daysAgo(24) },
  { id: "initech-cloud-4-slack", accountId: "initech-cloud", kind: "slack", summary: "Shared eval channel spun up; Priya asks about ISR in a monorepo", body: "Created #initech-cloud-eval with Priya and one teammate, Marcus Feld. Priya: 'Does ISR work if our app and marketing site live in the same Turborepo?' Sent monorepo build-config docs in reply. Channel is still just Priya and Marcus — no manager, no security or procurement presence.", source: "#initech-cloud-eval", occurredAt: daysAgo(33) },
  { id: "initech-cloud-5-call", accountId: "initech-cloud", kind: "call", summary: "First discovery call with Priya — current pain, no timeline", body: "30 min with Priya (Sr Frontend Eng). Pain: Netlify build times of ~8-9 min are slowing their PR review loop and previews feel sluggish. Team is 12 engineers, mostly Next.js 14 App Router. No compelling event, no approved budget — she called it 'a side investigation I'm running.' Confirmed there's no exec sponsor yet: her EM Dana Kwon 'knows I'm poking at it but isn't involved.'", source: "discovery call", occurredAt: daysAgo(40) },
  { id: "initech-cloud-6-email", accountId: "initech-cloud", kind: "email", summary: "Priya emails asking about preview deployments and seat pricing", body: "Inbound from Priya: 'We're evaluating whether to move our marketing site + app off Netlify. Two questions — how do preview deployments work per-PR, and what does Pro cost for a team of ~10 devs?' She signed as Senior Frontend Engineer. No mention of a manager, budget, or timeline — pure feature curiosity. Replied with a pricing overview and offered a 30-min intro call.", source: "inbound email", occurredAt: daysAgo(46) },
  { id: "initech-cloud-7-note", accountId: "initech-cloud", kind: "note", summary: "Priya Raman self-served onto Pro; logged as fresh SaaS discovery lead", body: "Automated alert: priya.raman@initechcloud.io upgraded a personal Hobby project to Pro and tagged the team 'Initech Cloud'. Company is a ~40-person SaaS building subscription-billing tooling; frontend is Next.js on Netlify today. Logged as a brand-new discovery lead — no prior contact and no opportunity in Salesforce yet.", source: "self-serve signup alert", occurredAt: daysAgo(52) },
  { id: "massive-dynamic-1-slack", accountId: "massive-dynamic", kind: "slack", summary: "Procurement confirms legal cleared the final MSA redlines", body: "Dana Reyes posted that legal signed off on the last two redlines — the limitation-of-liability cap and moving the auto-renewal notice window to 60 days. The order form is now sitting with Gerald Okafor for countersignature. Priya offered to nudge Gerald directly since he's out until Wednesday.", source: "#massive-dynamic-eval", occurredAt: daysAgo(3) },
  { id: "massive-dynamic-2-call", accountId: "massive-dynamic", kind: "call", summary: "Negotiated multi-year discount and annual payment terms", body: "Dana pushed hard for 22% off list on the 3-year commit; we landed at 18% in exchange for annual up-front billing instead of monthly. Confirmed the $980K ARR figure holds flat across all three years with a 5% uplift cap on the year-2 and year-3 true-ups. Dana wants the revised order form reflecting these terms back to her by Friday.", source: "procurement negotiation call", occurredAt: daysAgo(7) },
  { id: "massive-dynamic-3-meeting", accountId: "massive-dynamic", kind: "meeting", summary: "Mapped approval chain — CTO signature is the last gate", body: "Walked Massive Dynamic's approval path with Priya: platform eng and security have already endorsed, procurement is the active thread, and Gerald Okafor holds final signature. Priya confirmed budget is allocated in the current fiscal year and no competing vendor is still in the running. Only open item is closing the legal redline round.", source: "deal review sync", occurredAt: daysAgo(11) },
  { id: "massive-dynamic-4-email", accountId: "massive-dynamic", kind: "email", summary: "Sent formal quote — 3-yr Enterprise at $980K ARR", body: "Emailed the formal proposal and order form to Gerald Okafor and Dana Reyes for a 3-year Enterprise agreement at $980K ARR: 120 Pro seats, 8 concurrent build containers, Enterprise WAF + DDoS, 24/7 support with a named TAM, and 5 TB/mo committed bandwidth. Noted the quote is valid through end of Q3 FY26 and asked for redlines or a call to walk through the pricing build-up.", source: "quote email to economic buyer", occurredAt: daysAgo(18) },
  { id: "massive-dynamic-5-note", accountId: "massive-dynamic", kind: "note", summary: "Security review cleared — SOC 2 and pen test satisfied", body: "Aisha Bello's team signed off after reviewing our SOC 2 Type II, the latest pen-test summary, and confirming SSO/SCIM plus audit-log export meet their controls. No open findings, and they waived the extra DPA addendum since our standard terms already cover EU data residency. This unblocks commercial and clears the path to send pricing.", source: "security review", occurredAt: daysAgo(26) },
  { id: "massive-dynamic-6-call", accountId: "massive-dynamic", kind: "call", summary: "Scoped seats, builds, and bandwidth to size the quote", body: "Sizing call with Priya's team to right-size the contract: settled on 120 seats (up from 90 in the trial), 8 concurrent builds to handle their monorepo CI, and ~5 TB/mo bandwidth based on trailing 90-day usage. Priya flagged two internal teams migrating in Q4 that should drive year-2 expansion. Agreed I'd convert this into a formal quote.", source: "sizing & scoping call", occurredAt: daysAgo(34) },
  { id: "massive-dynamic-7-meeting", accountId: "massive-dynamic", kind: "meeting", summary: "POV readout — technical win, decision to go commercial", body: "Readout of the 6-week proof-of-value: the platform team cut preview-deploy time from 14 minutes to under 3 and consolidated three internal hosting setups onto Vercel. Priya secured a verbal from Gerald to proceed to a multi-year commercial agreement. Logged the technical win; agreed the next steps were sizing and a formal quote.", source: "POV readout", occurredAt: daysAgo(44) },
  { id: "northwind-logistics-1-slack", accountId: "northwind-logistics", kind: "slack", summary: "Priya confirms platform team availability, pushing for POV kickoff next week", body: "Priya messaged in #northwind-logistics-eval: 'Platform team has bandwidth starting Monday the 20th. Marcus and two of his engineers are ready to build the freight-tracking dashboard on the trial org. Can we get the sandbox + Enterprise trial keys provisioned so we're not blocked day one?' She flagged that go-live is committed for Sept 30 to align with peak-season traffic, so the POV needs to wrap in ~3 weeks.", source: "#northwind-logistics-eval", occurredAt: daysAgo(2) },
  { id: "northwind-logistics-2-note", accountId: "northwind-logistics", kind: "note", summary: "Drafted POV success criteria; 3 exit metrics agreed with Priya", body: "Aligned with Priya on 3 measurable POV exit criteria: (1) migrate the real-time carrier-tracking app to Next.js on Vercel and hit sub-1.5s LCP p75 on the shipment-detail route, (2) prove ISR + edge caching handles their 40k concurrent peak-season sessions, (3) SSO via Okta wired end-to-end. Scope is intentionally narrow to fit the Sept 30 go-live. Still need Derek's sign-off on the data-residency question before we can call it done.", source: "POV planning note", occurredAt: daysAgo(4) },
  { id: "northwind-logistics-3-meeting", accountId: "northwind-logistics", kind: "meeting", summary: "Technical deep-dive; team validated architecture fit, chose POV scope", body: "90-min technical deep dive with Priya, Marcus, and two platform engineers. Marcus walked through their current Netlify + self-managed Node setup and the cold-start pain on their tracking API. We whiteboarded moving the shipment-detail and dispatch dashboards to Vercel with Fluid Compute for the streaming tracking feed. Team was visibly sold on the DX; decision was to POV those two routes rather than the whole app to protect the timeline.", source: "technical deep-dive call", occurredAt: daysAgo(11) },
  { id: "northwind-logistics-4-email", accountId: "northwind-logistics", kind: "email", summary: "Derek (InfoSec) raises SOC 2 + data-residency questions before POV", body: "Derek Osei emailed: 'Before we stand up a trial I need the SOC 2 Type II report, and confirmation that shipment PII stays in US regions. We had a vendor last year default traffic to EU edge and it created a compliance headache.' He's not blocking the POV but wants the residency config documented as part of it. I sent the SOC 2 report and looped in our security SE to cover the region-pinning story.", source: "eng lead email thread", occurredAt: daysAgo(16) },
  { id: "northwind-logistics-5-call", accountId: "northwind-logistics", kind: "call", summary: "AM + CFO budget check; $310K confirmed, contingent on POV outcome", body: "Danielle and I had a short call with Lauren Tsai (CFO). Lauren confirmed the ~$310K Enterprise budget is earmarked in this fiscal year but was explicit: 'The budget's real, but I want to see the performance numbers from the trial before I sign.' She's neutral, deferring the technical judgment to Priya. This makes the POV the gating event for the deal.", source: "budget qualification call", occurredAt: daysAgo(23) },
  { id: "northwind-logistics-6-meeting", accountId: "northwind-logistics", kind: "meeting", summary: "Discovery: peak-season scaling pain surfaced as primary driver", body: "Initial discovery with Priya and Marcus. Their biggest pain is that self-managed infra buckles during Q4 peak shipping season; last November the tracking dashboard degraded for 6 hours during a Black Friday surge. Priya wants managed scaling and preview deployments for her 12-person frontend org. Strong technical fit surfaced early, which is why we're fast-tracking toward a POV.", source: "discovery call", occurredAt: daysAgo(34) },
  { id: "oscorp-energy-1-meeting", accountId: "oscorp-energy", kind: "meeting", summary: "Sizing workshop: locked seat count, deploy volume, and target regions", body: "Worked through projected usage with Reyes and Nair to size the deal: 45 concurrent developer seats across 3 teams (grid-ops, customer portal, internal tooling), roughly 120 preview deployments/day, and 2 production regions pinned to Frankfurt (fra1) and Dublin. Reyes wants to standardize on Enterprise; open question is whether Fluid Compute concurrency at their peak load needs a dedicated add-on. Action: I owe them a per-region cost breakdown and a confirmation that observability retention meets their 90-day requirement.", source: "sizing workshop", occurredAt: daysAgo(4) },
  { id: "oscorp-energy-2-slack", accountId: "oscorp-energy", kind: "slack", summary: "Procurement flagged fixed quarterly onboarding cadence; contract realistically Q4", body: "Liang Tao in #oscorp-energy-eval: their vendor onboarding runs on a fixed quarterly cadence, so the next hard gate is the Aug 5 architecture review board, and contract signature is realistically Q4 FY26 given legal + security sign-off sequencing. He asked that our quote stay valid through end of fiscal year and that the order form itemize the dedicated infra add-on separately from seats so his finance team can map it to the capex line.", source: "#oscorp-energy-eval", occurredAt: daysAgo(6) },
  { id: "oscorp-energy-3-email", accountId: "oscorp-energy", kind: "email", summary: "Security sent 140-question questionnaire; hard EU data-residency + on-prem ask", body: "Curt Connors requires that all build and runtime data remain in the EU and is pushing on whether Vercel can support self-hosted/BYOC build runners inside their own cloud account for the grid-ops workload. Attached a 140-question vendor security questionnaire and said procurement will not advance without SOC 2 Type II, a signed DPA, and a documented answer on data-residency guarantees. This is the critical path item before the Aug 5 review board.", source: "eng security email", occurredAt: daysAgo(9) },
  { id: "oscorp-energy-4-call", accountId: "oscorp-energy", kind: "call", summary: "Pricing/sizing call with AM: modeled ~$700K ACV, capping overage", body: "Call with Reyes, Tao, and Dana (AM) to align commercial shape. They want committed-use pricing with a hard cap on on-demand overage rather than pure usage-based. We modeled ~$700K ACV: 45 Enterprise seats + Enterprise support + a dedicated/secure-compute add-on for the EU-resident workload. Tao asked for a 3-year ramp option; I flagged that the dedicated infra line is still an estimate until security confirms the deployment topology.", source: "pricing call", occurredAt: daysAgo(12) },
  { id: "oscorp-energy-5-note", accountId: "oscorp-energy", kind: "note", summary: "Internal note: Connors is the gating risk; topology needs SE architecture review", body: "Internal read on the account: Connors is the real gate, not budget. The on-prem/data-residency constraint likely can't be satisfied by standard Enterprise alone and may need Vercel secure compute or a BYOC build pattern, so I've pulled in our platform SE to confirm feasibility before we commit numbers on the order form. Reyes is a strong champion and Nair is aligned on the infra side, but neither can override security. Do not send a final quote until the topology question is answered.", source: "account note", occurredAt: daysAgo(15) },
  { id: "oscorp-energy-6-email", accountId: "oscorp-energy", kind: "email", summary: "Osborn delegates security + procurement, supportive but budget-gated", body: "Norman Osborn replied to the recap looping in Connors and Tao directly: he's supportive of moving forward but is staying hands-off on the detail, saying he needs the total to land under his allocated FY26 budget and the security review to come back clean. He explicitly deferred the technical and procurement decisions to his team, which means we won't get exec air-cover until the numbers and the residency answer are both nailed down.", source: "VP eng email", occurredAt: daysAgo(20) },
  { id: "oscorp-energy-7-meeting", accountId: "oscorp-energy", kind: "meeting", summary: "POV concluded successfully; team greenlit move into sizing", body: "Wrap-up of the 4-week POV. Reyes confirmed the team validated ISR, preview deployments, and rollback behavior against their customer-portal workload and considers the technical evaluation a pass. She asked to move into commercial sizing and to start pulling in security and procurement, which kicks off this phase. Noted going in that the two things that could still derail it are EU data residency and their long quarterly procurement cycle.", source: "POV readout", occurredAt: daysAgo(28) },
  { id: "pied-piper-data-1-note", accountId: "pied-piper-data", kind: "note", summary: "Internal note — technical validation favors us; cost case + buyer are the gaps", body: "Technical validation is trending our direction on preview DX and edge performance, but the deal hinges on two things: the cost/lock-in narrative Devi owns, and a still-disengaged economic buyer in Marcus. Plan is to turn the reference architecture and the demo numbers into a real TCO model (infra spend + eng-time saved), scope a formal apples-to-apples comparison against Devi's in-house prototype, and get it in front of Marcus before his August budget review — real numbers, not slides. Bryce is a strong champion but explicitly said he doesn't own the final call.", source: "SE account notes", occurredAt: daysAgo(4) },
  { id: "pied-piper-data-2-slack", accountId: "pied-piper-data", kind: "slack", summary: "Bryce socializes the demo numbers; cost model + buyer still open", body: "Bryce recapped the technical eval in #pied-piper-data-eval: the Vercel reference deployment hit 38s median preview builds versus 5m50s on their current EKS pipeline, and docs TTFB of 62ms versus 180ms. Priya and two other frontend engineers reacted positively. Devi acknowledged the DX gap but reiterated he won't recommend anything until he sees a full egress + build-minutes cost model, and noted Marcus hasn't weighed in since the architecture deep dive.", source: "#pied-piper-data-eval", occurredAt: daysAgo(7) },
  { id: "pied-piper-data-3-call", accountId: "pied-piper-data", kind: "call", summary: "Technical eval — SE-demonstrated preview DX and edge perf", body: "Technical eval session: we deployed their production docs repo to a Vercel reference project to demonstrate the workflow live. Preview deploys landed in ~40s versus the ~6 min their current EKS pipeline takes, and edge TTFB on the docs site came in roughly 3x better. Devi's in-house prototype isn't finished — he's stuck getting cache-invalidation parity with ISR and admitted it's 'more plumbing than expected.' Cost is still the open question: Devi estimates in-house is cheaper at their current 4M req/mo but conceded the ongoing eng-time overhead is real.", source: "technical eval call", occurredAt: daysAgo(14) },
  { id: "pied-piper-data-4-meeting", accountId: "pied-piper-data", kind: "meeting", summary: "Working session — reference architecture + cost model walkthrough", body: "Working session to walk the reference architecture and first-pass cost model we owed them from the deep dive. Covered ISR + build cache for the 1,200-page docs repo and edge middleware for the console, against their ~4M monthly requests. Devi committed to standing up his own in-house prototype on EKS + Cloudflare to argue the build case in parallel. Marcus dropped in for 10 minutes, stayed neutral, and set the bar: he'll move on 'real numbers, not slides.'", source: "reference-architecture working session", occurredAt: daysAgo(22) },
  { id: "pied-piper-data-5-slack", accountId: "pied-piper-data", kind: "slack", summary: "Eval channel — team defines the criteria for a head-to-head", body: "In #pied-piper-data-eval the team settled on the four things any comparison would have to measure: cold build time, edge TTFB, DX for preview environments, and total cost at 4M req/mo. Priya said preview-per-PR alone would save the frontend team several hours weekly. Devi countered that before anyone commits he'd want to stand up an in-house prototype on their existing EKS + Cloudflare stack to compare 'apples to apples.'", source: "#pied-piper-data-eval", occurredAt: daysAgo(30) },
  { id: "pied-piper-data-6-meeting", accountId: "pied-piper-data", kind: "meeting", summary: "Architecture deep dive — ISR, edge middleware, egress cost", body: "90-minute technical session with Bryce, Priya, and Devi. We walked through ISR revalidation for the 1,200-page docs site, edge middleware for the console's auth gate, and how the build cache works across preview deploys. Devi pushed hard on egress cost and vendor lock-in and asked whether ISR could be replicated with their own Redis + CDN. Left with an action to send a reference architecture and a cost model for their ~4M monthly requests.", source: "architecture review call", occurredAt: daysAgo(38) },
  { id: "pied-piper-data-7-email", accountId: "pied-piper-data", kind: "email", summary: "Bryce emails eval scope; Devi signals a build-in-house comparison", body: "Bryce sent over the evaluation goals: preview deploys per PR, ISR for their 1,200-page docs site, and edge middleware for auth-gating the console. He copied Devi Ramaswamy, who replied that the team should also benchmark 'what it would take to build the same on our existing infra.' First clear signal they're weighing us against building in-house.", source: "eng lead email", occurredAt: daysAgo(46) },
  { id: "pied-piper-data-8-call", accountId: "pied-piper-data", kind: "call", summary: "Discovery — mapping the frontend + docs delivery pain", body: "First call with Bryce Nakamura (Staff Platform Eng) and Priya Anand. They run their developer console and docs on a homegrown Next.js setup deployed to their own EKS cluster; preview environments are manual and builds take ~6 minutes. Bryce estimated the team spends roughly a day a week babysitting the deploy pipeline. No hard timeline yet, but Marcus (VP Eng) wants a build-vs-buy recommendation before FY26 H2 planning.", source: "discovery call", occurredAt: daysAgo(54) },
  { id: "soylent-foods-1-slack", accountId: "soylent-foods", kind: "slack", summary: "Priya asks to push the follow-up call a week — mid-sprint", body: "Priya messaged in the shared channel: 'Hey, can we bump Thursday to the following week? We're mid-sprint on the subscription revamp and I don't want to half-pay-attention.' She added that she still wants to talk but there's 'no fire' on their side. I said no problem and reminded her about the couple of concrete stack examples she'd said she'd pull together on our intro call, so the regroup isn't starting from scratch.", source: "#soylent-foods-eval", occurredAt: daysAgo(3) },
  { id: "soylent-foods-2-note", accountId: "soylent-foods", kind: "note", summary: "Internal note: still no defined project — treat as early discovery", body: "Logging where this stands: inbound from a webform, one intro call done, but there's no named project, budget, or timeline yet. Priya is curious and technically sharp, but Marcus (VP Eng) hasn't engaged and DTC/marketing (Tara) has a separate agenda. Keeping this low priority until someone articulates a real pain we can map to Vercel. Not forecasting.", source: "SE CRM note", occurredAt: daysAgo(6) },
  { id: "soylent-foods-3-call", accountId: "soylent-foods", kind: "call", summary: "30-min intro call — pain is fuzzy, mostly exploring", body: "First call with Priya and Tara. They're on a self-managed Next.js app on AWS (EC2 + their own CI), and Priya admitted 'it works, it's just annoying to deploy and preview.' No hard metrics on build times or downtime — when I asked for numbers she said she'd have to check. Tara cares about marketing landing pages being slow to ship but couldn't say how many they publish. Left it as: they'll gather a couple concrete examples and we'll regroup.", source: "intro call", occurredAt: daysAgo(11) },
  { id: "soylent-foods-4-email", accountId: "soylent-foods", kind: "email", summary: "Sent agenda + 3 qualifying questions ahead of intro call", body: "Emailed Priya a light agenda before the call and asked three things: what's the app built on, what's the single most painful part of shipping today, and who else feels that pain. She replied only to the first ('Next.js 14, App Router, hosted on our own EC2') and skipped the other two, which tells me the pain isn't yet crisp enough for them to articulate. No mention of a deadline or evaluation.", source: "eng lead email", occurredAt: daysAgo(15) },
  { id: "soylent-foods-5-slack", accountId: "soylent-foods", kind: "slack", summary: "Connected in shared channel; Priya says 'just exploring for now'", body: "Spun up the shared Slack connect channel after the form came in. Priya's opener: 'Thanks for reaching out — honestly just exploring for now, saw Vercel come up when we were griping about our deploy setup.' I asked what triggered the griping and she said preview environments and a flaky self-hosted CI, but framed it as a nice-to-have, not a mandate from above.", source: "#soylent-foods-eval", occurredAt: daysAgo(19) },
  { id: "soylent-foods-6-note", accountId: "soylent-foods", kind: "note", summary: "Inbound lead triage — routed from marketing webform", body: "Account created from an inbound 'contact sales' form submitted by Priya Anand at Soylent Foods (DTC food/agtech, ~$150k spend range on infra per Devon's read). Form comment was one line: 'Curious about Vercel for our Next.js app, evaluating options.' No company-wide initiative attached. AM Devon Whitaker flagged it as low-intent but worth a discovery touch given they're already on Next.js.", source: "inbound lead form", occurredAt: daysAgo(24) },
  { id: "stark-industries-1-email", accountId: "stark-industries", kind: "email", summary: "Sent scoping worksheet to Lena; awaiting final seat/region counts", body: "Emailed Lena Reyes the Enterprise scoping worksheet with three sizing scenarios: 40, 65, and 80 Pro seats. She confirmed the platform team is ~65 developers today but wants to reserve room for the two teams migrating off the legacy Jenkins pipeline in FY27. Still need her to lock the final concurrent build minutes tier and whether they need one or two production regions (US-East plus a GovCloud-adjacent option came up).", source: "AM handoff email thread", occurredAt: daysAgo(3) },
  { id: "stark-industries-2-slack", accountId: "stark-industries", kind: "slack", summary: "Arjun confirmed technical win signed off; pushing internally on scope", body: "Arjun pinged in #stark-industries-eval: 'POV results are locked, everyone's happy with the preview deploy times and the DDoS numbers from the load test.' He's now helping me pin down the actual seat count and said Lena wants the quote to separate build concurrency from observability add-ons so procurement can line-item it. Asked me for a per-seat vs. committed-spend comparison before Thursday.", source: "#stark-industries-eval", occurredAt: daysAgo(5) },
  { id: "stark-industries-3-call", accountId: "stark-industries", kind: "call", summary: "AE sync with Dana to prep quote inputs and handoff", body: "Called Dana Whitfield to align on the handoff. Walked her through the technical win, the 65-seat baseline, the 8TB bandwidth sizing, and the observability add-on Lena wants scoped separately. Dana flagged that legal and procurement (Priya Nair) will need the MSA redlines started in parallel or we lose the Q4 close. Action: I finalize the scoping sheet, Dana drafts the commercial quote.", source: "AE sync call", occurredAt: daysAgo(9) },
  { id: "stark-industries-4-meeting", accountId: "stark-industries", kind: "meeting", summary: "Sizing workshop: mapped current usage to Enterprise tiers", body: "Ran a 60-min sizing workshop with Arjun, Tom Becker, and Lena. Pulled their current monthly build minutes (~180k) and bandwidth (~4.2TB egress) from the trial dashboard and mapped it to the Enterprise concurrency tier. Tom flagged that image optimization traffic will roughly double once the marketing site consolidates in, so we sized to 8TB to be safe. Agreed the quote needs 65 seats as the baseline with an expansion clause.", source: "sizing workshop notes", occurredAt: daysAgo(12) },
  { id: "stark-industries-5-note", accountId: "stark-industries", kind: "note", summary: "Security review still open; David Cho wants SOC 2 + data residency answers", body: "Logging that David Cho's app-sec review is the main open risk before signature. He's asked for our SOC 2 Type II report, the DPA, and written confirmation on where build logs and edge cache data reside. He was skeptical about the third-party subprocessor list on the call. This is a procurement/legal gate ahead, not a technical blocker to sizing, so proceeding with scoping in parallel while security answers get routed.", source: "internal note", occurredAt: daysAgo(16) },
  { id: "stark-industries-6-email", accountId: "stark-industries", kind: "email", summary: "Procurement intro from Priya; vendor onboarding forms incoming", body: "Priya Nair (procurement) introduced herself over email and attached Stark's standard vendor onboarding packet plus a security questionnaire. She noted any contract over $1M requires a competitive justification memo and VP sign-off, so timing is tight for Q4. Confirmed she needs the final quote value before she can open the PO workflow, which is exactly why nailing the seat/bandwidth scope this week matters.", source: "procurement intro email", occurredAt: daysAgo(21) },
  { id: "stark-industries-7-meeting", accountId: "stark-industries", kind: "meeting", summary: "POV readout: technical win formally accepted by Lena", body: "POV readout meeting with Lena, Arjun, and David. Presented the results: preview deploys dropped from 11 min on their old stack to under 90 seconds, and the Firewall load test held at 40k rps with zero origin impact. Lena said 'this clears our bar, let's talk numbers' - the formal technical win. She asked us to move to sizing and get a quote in front of her before end of quarter.", source: "POV readout deck", occurredAt: daysAgo(27) },
  { id: "tyrell-bio-1-email", accountId: "tyrell-bio", kind: "email", summary: "Inbound from Priya Nair — Netlify previews breaking their QA flow", body: "Priya emailed after our Next.js Conf talk asking whether Vercel could fix their preview-deploy reliability — Netlify builds for the researcher portal run 12-14 min and per-branch previews fail roughly 1 in 4 times. She flagged three frontend teams (~40 engineers) blocked on QA sign-off. Asked to get her VP Eng, Marcus Webb, into a first real working session.", source: "inbound email", occurredAt: daysAgo(46) },
  { id: "tyrell-bio-2-call", accountId: "tyrell-bio", kind: "call", summary: "30-min scoping call with Priya + James Tan to frame the new business meeting", body: "Ran a scoping call with Priya and Sr Frontend Lead James Tan ahead of the exec session. Mapped the current stack: Next.js researcher portal self-hosted on AWS ECS plus Netlify Enterprise for marketing and docs — they pay for both and duplicate CI. James wants Turbopack build times and real per-branch previews; we agreed to bring VP Eng Marcus Webb to a formal new business meeting the following week.", source: "discovery call", occurredAt: daysAgo(41) },
  { id: "tyrell-bio-3-meeting", accountId: "tyrell-bio", kind: "meeting", summary: "New business meeting with VP Eng Marcus Webb, Priya, James — pains + Vercel value walkthrough", body: "First formal new business meeting: 45 min with Marcus Webb (VP Eng), Priya, and James. Walked their top three pains — 14-min Netlify builds, flaky previews, and the ECS preview infra they maintain by hand — and mapped each to Vercel previews, the Fluid Compute cost model, and Turbopack. Marcus was engaged on the DX story but explicitly said 'no numbers commitment today' and asked us to come back with a consolidated cost picture vs. their current Netlify + AWS spend. No POV or scoping discussed yet — he wants the business case first.", source: "new business meeting", occurredAt: daysAgo(33) },
  { id: "tyrell-bio-4-email", accountId: "tyrell-bio", kind: "email", summary: "Sent Marcus the meeting recap + preview-deploy one-pager and rough cost side-by-side", body: "Emailed Marcus and Priya a recap of the new business meeting with a one-pager on preview deployments and Fluid Compute, plus a rough side-by-side of Vercel vs. their Netlify Enterprise (~$160k) and ECS preview infra (~$90k/yr). Proposed a follow-up to align on a value case and, if it lands, a small POV on the researcher portal. Marcus replied 'thanks, will review with the team' but didn't book time.", source: "follow-up email", occurredAt: daysAgo(30) },
  { id: "tyrell-bio-5-slack", accountId: "tyrell-bio", kind: "slack", summary: "Budget-freeze rumor surfaces — Priya hears new SaaS spend is paused", body: "Priya pinged the eval channel: 'heads up, hearing finance may freeze new SaaS commits — Series C close slipped to Q4 so Dana's team is reviewing all H2 vendor spend.' She's still bought in but warned Marcus won't sign anything new until the freeze question is resolved. First real sign the deal is at risk.", source: "#tyrell-bio-eval", occurredAt: daysAgo(18) },
  { id: "tyrell-bio-6-call", accountId: "tyrell-bio", kind: "call", summary: "Priya confirms freeze is real — FinOps wants ROI before any new vendor", body: "Confirmed with Priya the freeze is real, not just chatter: FinOps director Dana Okoro is gatekeeping all net-new SaaS until the H2 review after the Series C slipped. Marcus has gone quiet — no reply to two emails. Priya's advice: don't push for a POV, arm her with a hard consolidation ROI (Netlify + ECS savings plus eng hours) she can carry into Dana's review. She thinks framing it as cost-neutral consolidation, not new spend, is the only way through.", source: "champion call", occurredAt: daysAgo(11) },
  { id: "tyrell-bio-7-note", accountId: "tyrell-bio", kind: "note", summary: "At risk on budget freeze — need consolidation value case for Dana's H2 review", body: "Deal is parked at the new business meeting stage: the exec session landed well but Marcus won't move without a business case, and now a budget freeze (Dana Okoro / FinOps, post-Series-C slip) has stalled everything. Need a sharp value case that reframes Vercel as consolidation — retire ~$160k Netlify + ~$90k ECS preview infra, free ~1.5 eng FTE — rather than new spend, and get it in front of Dana before the H2 review closes. Marcus is unengaged; Priya is the only path in right now.", source: "account note", occurredAt: daysAgo(4) },
  { id: "umbrella-health-1-slack", accountId: "umbrella-health", kind: "slack", summary: "Dana confirms InfoSec is looping in; asking us for a BAA + HIPAA one-pager", body: "Dana Whitfield pinged the shared channel: 'Good news, Marcus's team agreed to review Vercel as a potential vendor. Before we go deeper he needs to see whether you'll sign a BAA and how PHI is handled at the edge.' She asked me to send a HIPAA/security one-pager and the SOC 2 Type II report by end of week so InfoSec can start their intake. No technical deep dive gets scheduled until security signs off on scope.", source: "#umbrella-health-eval", occurredAt: daysAgo(4) },
  { id: "umbrella-health-2-email", accountId: "umbrella-health", kind: "email", summary: "Marcus (InfoSec) sends guarded intro, wants BAA + data-residency answers first", body: "Marcus Bell replied to my intro email: 'Appreciate the overview, but before my team spends cycles on a proof-of-concept I need to understand three things — do you sign a Business Associate Agreement, where does patient data physically reside, and can we get your latest pen-test summary?' Tone is skeptical but not closed. He explicitly said a deeper technical evaluation is premature until these HIPAA and security-review prerequisites are answered.", source: "eng lead email thread", occurredAt: daysAgo(8) },
  { id: "umbrella-health-3-note", accountId: "umbrella-health", kind: "note", summary: "Internal note: qualify HIPAA scope before proposing POV", body: "Logging after the intro-meeting debrief with Priya (AM). We agreed not to push a POV or scoping conversation yet — Umbrella is squarely in a new-business-meeting posture. Key open question is whether their patient-portal workloads actually touch PHI on Vercel infra or just serve a static/SSR shell with PHI staying in their AWS backend. That determination drives whether a BAA is even required. Next milestone is a security-requirements confirmation call, not a demo.", source: "internal CRM note", occurredAt: daysAgo(11) },
  { id: "umbrella-health-4-call", accountId: "umbrella-health", kind: "call", summary: "Sofia (staff eng) technical color: excited about previews, worried about compliance", body: "Follow-up call with Sofia Ramanathan after the group meeting. She's genuinely enthusiastic about preview deployments and Turbopack build times — said it would 'save us a day a sprint.' But she cautioned that Marcus in InfoSec has killed two prior SaaS evaluations over data-handling concerns, so getting him a clean HIPAA story early is the make-or-break. She offered to help gather the internal data-flow diagram we'd need to answer the PHI-at-the-edge question.", source: "discovery call", occurredAt: daysAgo(13) },
  { id: "umbrella-health-5-meeting", accountId: "umbrella-health", kind: "meeting", summary: "New business meeting: platform pain, DX goals, no commitments yet", body: "First real working meeting with Dana Whitfield and Sofia Ramanathan. They walked us through their current setup — a self-managed Next.js app on ECS, ~40s cold builds and painful preview environments for their 22-person frontend org. Dana framed the interest as 'exploring whether Vercel could take the platform burden off my team.' No budget, timeline, or success criteria defined yet; they repeatedly flagged that healthcare procurement means security review comes before any pilot. Left as an early-stage fit conversation.", source: "new business meeting (Zoom)", occurredAt: daysAgo(15) },
  { id: "umbrella-health-6-email", accountId: "umbrella-health", kind: "email", summary: "Priya (AM) intro email connecting us to Greg (CTO) and Dana", body: "Priya Raghunathan sent the initial intro connecting me with Greg Olsen (SVP Digital/CTO) and Dana Whitfield. Greg replied briefly — 'Dana owns this evaluation, she'll drive; I'll want to see the security and cost picture before it goes anywhere' — then went quiet. He's the economic buyer but currently hands-off and unengaged. Established Dana as the day-to-day sponsor and set up the first business meeting.", source: "AM intro email", occurredAt: daysAgo(24) },
  { id: "umbrella-health-7-note", accountId: "umbrella-health", kind: "note", summary: "Inbound origin: Dana requested a conversation after Next.js Conf", body: "Recording deal origin for context. Dana Whitfield reached out via the website after attending a Next.js Conf talk on Fluid Compute; she named build performance and preview environments as the specific hooks. Warm inbound, medium-sized frontend org, plausible six-figure fit — but this is day one of the relationship. Flagged healthcare/HIPAA as an early gating risk from the outset.", source: "inbound lead note", occurredAt: daysAgo(30) },
  { id: "vandelay-travel-1-call", accountId: "vandelay-travel", kind: "call", summary: "Discovery call: peak-season traffic spikes crushing legacy Rails booking pages", body: "Deepa Krishnan (Staff Eng) and Tomás Rivera walked through the core pain: hotel search and detail pages run on a legacy Rails/jQuery stack with mobile LCP around 4.2s, and summer peak traffic (~3x baseline) forces manual, error-prone scaling. QA is also bottlenecked with no per-branch preview environments. We framed a Next.js on Vercel migration for the customer-facing storefront and agreed to a scoped POV on the hotel-detail template.", source: "discovery call", occurredAt: daysAgo(52) },
  { id: "vandelay-travel-2-meeting", accountId: "vandelay-travel", kind: "meeting", summary: "POV kickoff — scoped hotel-detail + search POC with three exit criteria", body: "Locked POV success criteria with Deepa: mobile LCP under 2s (p75), ISR across the ~40k hotel pages, and a green load test at 3x peak concurrency (~9k RPS). Tomás owns wiring a read-only feed from their inventory API. Gordon Mercer (VP Eng) joined the final 10 minutes — supportive of the direction but flagged that budget is frozen until after the summer peak.", source: "POV kickoff (meeting)", occurredAt: daysAgo(44) },
  { id: "vandelay-travel-3-slack", accountId: "vandelay-travel", kind: "slack", summary: "Eng team sold on preview deployments mid-build; Edge Middleware unblocks geo redirects", body: "Deepa in #vandelay-travel-eval: 'preview URLs per PR just killed our staging queue — QA cleared 3 PRs before lunch.' Tomás confirmed ISR working across ~40k hotel pages with on-demand revalidation fired from their inventory webhook. Only snag was their currency/geo redirect logic; I pointed them to Edge Middleware and they had a working prototype the next day.", source: "#vandelay-travel-eval", occurredAt: daysAgo(33) },
  { id: "vandelay-travel-4-email", accountId: "vandelay-travel", kind: "email", summary: "Deepa emails POC benchmarks — LCP 4.2s → 1.6s, builds 11min → 90s", body: "Deepa sent the POC numbers: mobile LCP dropped from 4.2s to 1.6s (p75), TTFB down to ~180ms via edge caching, and build times of ~90s with Turbopack versus their 11-minute legacy pipeline. Her note: 'this is the number that'll get Gordon's attention.' She asked for help tuning the k6 load-test config ahead of the readout.", source: "eng lead email", occurredAt: daysAgo(26) },
  { id: "vandelay-travel-5-call", accountId: "vandelay-travel", kind: "call", summary: "POV readout: all three exit criteria met, eng + security sign off — technical win", body: "Readout with Deepa, Tomás, Gordon, and security's Wendy Okafor. The load test held at 9,200 RPS with p95 latency of 240ms (criteria was 9k / green), and all three POV exit criteria passed. Deepa formally recommended Vercel as the storefront platform, and Wendy confirmed the WAF plus SOC 2 / DPA satisfy her review with no blockers. Gordon said 'technically I'm sold' but reiterated there's no new spend until the seasonal budget reopens.", source: "POV readout (call)", occurredAt: daysAgo(18) },
  { id: "vandelay-travel-6-slack", accountId: "vandelay-travel", kind: "slack", summary: "Champion confirms internal decision made; deal gated only on seasonal budget window", body: "Deepa DM'd: 'internal call is made — we're going Vercel for the storefront, just need Gordon's budget window.' She explained the fiscal freeze runs through the summer peak (lifts after Labor Day) and that scoping and procurement can't kick off until it clears. No competitor is in play; the only risk is timing, not the technology.", source: "#vandelay-travel-eval", occurredAt: daysAgo(12) },
  { id: "vandelay-travel-7-note", accountId: "vandelay-travel", kind: "note", summary: "Internal: technical win locked, holding for post-peak budget to open scoping", body: "Technical win is solid — every POV exit criterion met, eng and security both bought in, no competitive threat. The deal is purely gated on Vandelay's seasonal budget freeze lifting after Labor Day. Scoping prep to stage now: collaborator/seat count, prod project + WAF + observability sizing, and a rough Enterprise quote against the current 230k ARR baseline. Reach out to Gordon early September.", source: "SE deal notes", occurredAt: daysAgo(8) },
  { id: "wonka-retail-1-meeting", accountId: "wonka-retail", kind: "meeting", summary: "POV kickoff — scope locked to storefront collections/product routes", body: "Ran the POV kickoff with Charlie Bucket and Mike Teavee. Agreed scope: migrate the /collections and /products routes of wonka.shop to Next.js App Router on Vercel and benchmark head-to-head against their current Fastly + EC2 stack. Charlie is forking the repo this week; target is a working preview deployment by end of month.", source: "POV kickoff call", occurredAt: daysAgo(38) },
  { id: "wonka-retail-2-email", accountId: "wonka-retail", kind: "email", summary: "Success criteria signed off by Veruca — peak-load is the make-or-break gate", body: "Sent the POV success-criteria doc and Veruca Salt approved three exit gates: p75 LCP under 1.5s on collections, sustain 40k rps at peak with no error-rate regression, and ISR revalidation wired to their Akeneo PIM. She was explicit that budget is 'contingent on the peak-load number,' making BFCM scaling the deciding metric.", source: "eng lead email thread", occurredAt: daysAgo(33) },
  { id: "wonka-retail-3-slack", accountId: "wonka-retail", kind: "slack", summary: "Preview env live — every PR building, ISR revalidating off staging Akeneo", body: "Charlie got the fork deploying to Vercel and previews are now building on every PR in the eval channel. First ISR test on /collections/candy is revalidating against a staging Akeneo feed. He flagged one snag — their monorepo build was 14 min; we turned on remote caching and it dropped to under 4.", source: "#wonka-retail-eval", occurredAt: daysAgo(27) },
  { id: "wonka-retail-4-call", accountId: "wonka-retail", kind: "call", summary: "Scaling deep-dive — 40k rps peak-season concerns, security asks surface", body: "Call with Charlie and Prisha Nadkarni on peak scaling. Last BFCM they peaked at ~40k rps and are nervous about function concurrency and cold starts under that spike. Walked them through Fluid Compute and concurrency scaling; Prisha wants a real load test to hit the numbers before she'll sign off, and asked for our SOC 2 report plus a WAF and data-residency overview.", source: "scaling deep-dive call", occurredAt: daysAgo(19) },
  { id: "wonka-retail-5-note", accountId: "wonka-retail", kind: "note", summary: "Load test hit 42k rps at 1.3s LCP — gates 1 & 2 green", body: "Ran the k6 load test against the Vercel preview: sustained 42k rps for 10 minutes with p75 LCP at 1.3s on /collections (down from 2.8s on their Fastly stack) and error rate flat at 0.02%. Two of the three exit gates are now green. Remaining open item is the Akeneo ISR revalidation edge case that fires on bulk price updates.", source: "POV progress note", occurredAt: daysAgo(12) },
  { id: "wonka-retail-6-slack", accountId: "wonka-retail", kind: "slack", summary: "Charlie: 'fastest our storefront has ever felt — the team is sold'", body: "Charlie posted the Lighthouse run in the eval channel — collections page went from 61 to 96 on performance. His words: 'honestly this is the fastest our storefront has ever felt, the team is sold.' Mike added that on-demand ISR fixed the stale-price bug that's been open in their backlog for months.", source: "#wonka-retail-eval", occurredAt: daysAgo(7) },
  { id: "wonka-retail-7-meeting", accountId: "wonka-retail", kind: "meeting", summary: "POV checkpoint — eng bought in, security sign-off is the remaining gate", body: "Mid-POV checkpoint with Charlie, Mike, and Veruca. Eng is clearly bought in and Veruca acknowledged the load numbers 'answered the peak question.' She's now gating on Prisha's security sign-off — needs the SOC 2 report, a pen-test summary, and SAML SSO for the Vercel dashboard confirmed. Agreed to close the ISR bulk-update item and reconvene for a go/no-go once security clears.", source: "POV checkpoint meeting", occurredAt: daysAgo(4) },
];
